import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static const String _authTokensKey = 'auth_tokens';
  static const String _userDataKey = 'user_data';
  final SharedPreferences _prefs;

  AuthManager(this._prefs);

  Future<void> login(Map<String, dynamic> userData, Map<String, dynamic> authTokens) async {
    await _prefs.setString(_userDataKey, jsonEncode(userData));
    await _prefs.setString(_authTokensKey, jsonEncode(authTokens));
  }

  Map<String, dynamic> getAuthTokens() {
    return jsonDecode(_prefs.getString(_authTokensKey) ?? '');
  }

  Map<String, dynamic> getUserData() {
    return jsonDecode(_prefs.getString(_userDataKey) ?? '');
  }

  bool isLoggedIn() {
    final authTokens = getAuthTokens();
    final userData = getUserData();
    return authTokens.isNotEmpty && userData.isNotEmpty;
  }
}

// Example usage
void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  final prefs = await SharedPreferences.getInstance();
  final authManager = AuthManager(prefs);

  // Login user
  await authManager.login(
    {
      'name': 'John Doe',
      'email': 'john@example.com'
    },
    {
      'token': 'your_token_here',
      'expiresAt': DateTime.now().millisecondsSinceEpoch + 3600 * 24
    }
  );

  // Check if user is logged in
  if (authManager.isLoggedIn()) {
    final userData = authManager.getUserData();
    final authTokens = authManager.getAuthTokens();

    print('User data: $userData');
    print('Auth tokens: $authTokens');
  } else {
    print('User is not logged in');
  }
